import{_ as s,o as i,c as e,ag as n}from"./chunks/framework.CXIqMST4.js";const u=JSON.parse('{"title":"第一次让 Codex 改代码","description":"","frontmatter":{},"headers":[],"relativePath":"guide/02-first-run.md","filePath":"guide/02-first-run.md","lastUpdated":1777684488000}'),l={name:"guide/02-first-run.md"};function t(p,a,d,h,o,r){return i(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="第一次让-codex-改代码" tabindex="-1">第一次让 Codex 改代码 <a class="header-anchor" href="#第一次让-codex-改代码" aria-label="Permalink to &quot;第一次让 Codex 改代码&quot;">​</a></h1><p>第一次实战不要选“重构整个项目”。选一个小、可验证、失败也容易回滚的任务。</p><h2 id="推荐任务" tabindex="-1">推荐任务 <a class="header-anchor" href="#推荐任务" aria-label="Permalink to &quot;推荐任务&quot;">​</a></h2><p>适合新手的任务：</p><ul><li>修复一个文案错别字。</li><li>给一个纯函数补测试。</li><li>更新 README 里的过期命令。</li><li>解释一个小模块，并补充必要注释。</li><li>修复一个已经有失败测试覆盖的 bug。</li></ul><p>不适合第一次尝试的任务：</p><ul><li>大规模架构重构。</li><li>跨多个服务的迁移。</li><li>没有测试的核心业务逻辑改动。</li><li>涉及生产凭据、账单、权限和删除数据的操作。</li></ul><h2 id="一个可直接复制的任务说明" tabindex="-1">一个可直接复制的任务说明 <a class="header-anchor" href="#一个可直接复制的任务说明" aria-label="Permalink to &quot;一个可直接复制的任务说明&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请修复当前仓库中最小范围的一个测试失败。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>要求：</span></span>
<span class="line"><span>1. 先运行测试，确认失败信息。</span></span>
<span class="line"><span>2. 阅读相关代码和测试，不要做无关重构。</span></span>
<span class="line"><span>3. 修改最少必要文件。</span></span>
<span class="line"><span>4. 修复后重新运行相关测试。</span></span>
<span class="line"><span>5. 最后总结：失败原因、改了哪些文件、验证命令和剩余风险。</span></span></code></pre></div><h2 id="观察-codex-的过程" tabindex="-1">观察 Codex 的过程 <a class="header-anchor" href="#观察-codex-的过程" aria-label="Permalink to &quot;观察 Codex 的过程&quot;">​</a></h2><p>重点看四件事：</p><ul><li>它有没有先读上下文。</li><li>它有没有控制改动范围。</li><li>它有没有运行验证命令。</li><li>它有没有诚实说明没能验证的部分。</li></ul><h2 id="你可以如何接住结果" tabindex="-1">你可以如何接住结果 <a class="header-anchor" href="#你可以如何接住结果" aria-label="Permalink to &quot;你可以如何接住结果&quot;">​</a></h2><p>完成后请自己再看一遍 diff：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> diff</span></span></code></pre></div><p>如果结果满意，再提交：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;fix: resolve failing test&quot;</span></span></code></pre></div><p>Codex 可以极大加速你，但最终合并代码的人仍然要对代码负责。</p>`,18)])])}const k=s(l,[["render",t]]);export{u as __pageData,k as default};
